A distributed counter must handle millions of increments per second (viral posts) without database bottlenecks.

**Naive Approach (doesn't scale):**
```sql
UPDATE posts SET like_count = like_count + 1 WHERE post_id = ?;
-- This creates a hot row → serialized writes → max ~1000 writes/sec
```

**Solution 1: Redis Atomic Increment**
```python
import redis
r = redis.Redis(cluster_mode=True)

def add_reaction(post_id: str, user_id: str, reaction: str):
    pipe = r.pipeline()
    # Atomic increment
    pipe.incr(f"reactions:{post_id}:{reaction}")
    # Track user reaction (for toggle/undo and dedup)
    pipe.sadd(f"reacted:{post_id}", f"{user_id}:{reaction}")
    pipe.execute()

def get_reaction_counts(post_id: str) -> dict:
    reactions = ['like', 'love', 'haha', 'wow', 'sad', 'angry']
    pipe = r.pipeline()
    for r_type in reactions:
        pipe.get(f"reactions:{post_id}:{r_type}")
    results = pipe.execute()
    return {r: int(v or 0) for r, v in zip(reactions, results)}
```

**Solution 2: Sharded Counters (for massive scale)**
```java
public class ShardedCounter {
    private static final int SHARDS = 100;
    private final RedisTemplate<String, Long> redis;

    public void increment(String counterId) {
        int shard = ThreadLocalRandom.current().nextInt(SHARDS);
        String key = "counter:" + counterId + ":shard:" + shard;
        redis.opsForValue().increment(key);
    }

    public long getCount(String counterId) {
        long total = 0;
        List<String> keys = IntStream.range(0, SHARDS)
            .mapToObj(i -> "counter:" + counterId + ":shard:" + i)
            .collect(Collectors.toList());
        List<Long> values = redis.opsForValue().multiGet(keys);
        for (Long v : values) if (v != null) total += v;
        return total;
    }
}
// Write throughput: 100 shards × 100K Redis ops/sec = 10M increments/sec
```

